-- Chien -> humain, Anniversaire, Volume 3

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Joyeux anniversaire. J''avais préparé un discours.',$$Joyeux anniversaire. J''avais préparé un discours.
Je l''avais élaboré cette nuit. Entre 2h et 4h du matin pendant que tu dormais. Les mots. L''ordre. Le moment fort au milieu. La conclusion qui fait quelque chose. C''était bien. Vraiment bien. Et puis ce matin tu t''es levé et tu as dit mon prénom avec la voix douce et tout s''est effacé d''un coup. Je me souviens plus d''un mot. Il ne reste que toi et cette journée. Joyeux anniversaire, mon humain préféré.
Avec discours perdu et ce qui reste infiniment mieux que les mots, — {prenom}, ton animal orateur dont le cœur parle plus fort que la tête 🎤$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Tu dors différemment la nuit de ton anniversaire.',$$Joyeux anniversaire. Tu dors différemment la nuit de ton anniversaire.
Je le sais parce que je surveille. Cette nuit tu t''es retourné moins souvent. Ta respiration était plus régulière. Plus profonde. Comme quelqu''un qui a passé une bonne journée et le sait encore en dormant. Moi au bout du lit je regardais ça et je me disais que c''était ça réussir un anniversaire. Que ça se lit jusque dans le sommeil. Joyeux anniversaire, mon humain préféré.
Avec veille nocturne assurée et diagnostic du sommeil d''anniversaire établi avec satisfaction, — {prenom}, ton animal gardien de tes nuits les plus heureuses 🌙$$,'touching',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai gardé un œil sur le gâteau pendant toute la préparation.',$$Pour ton anniversaire j''ai gardé un œil sur le gâteau pendant toute la préparation.
Deux heures. Tu mesurais. Tu mélangeais. Tu enfournais. Tu surveillais. Et moi je surveillais que tu surveilles. Assis à distance réglementaire. Sans approcher. Sans tendre la patte. Juste là. Présent. Attentif. Prêt à intervenir si quelque chose tombait. Rien n''est tombé. C''était décevant mais professionnel. Joyeux anniversaire, mon humain préféré.
Avec surveillance du processus de fabrication assurée et déception professionnelle gérée avec dignité, — {prenom}, ton animal contrôleur qualité pâtissier sans indemnités 🎂$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends toujours pas pourquoi tout le monde chante faux en même temps.',$$Joyeux anniversaire. Je comprends toujours pas pourquoi tout le monde chante faux en même temps.
C''est une question que je me pose chaque année. Vous connaissez tous la chanson. Vous la chantez souvent. Et pourtant le soir de l''anniversaire quelque chose se dérègle. Les voix partent dans des directions différentes. Le tempo flotte. Et vous souriez tous en chantant faux comme si c''était exactement ça qu''il fallait faire. J''ai aboyé une fois pour remettre le ton. On m''a pas écouté. Joyeux anniversaire, mon humain préféré.
Avec intervention musicale non sollicitée et problème de justesse collectif non résolu, — {prenom}, ton animal chef de chœur dont l''autorité reste à établir 🎵$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Quelqu''un t''a souhaité avant moi ce matin.',$$Joyeux anniversaire. Quelqu''un t''a souhaité avant moi ce matin.
Le téléphone a sonné à 8h12. Avant que j''aie eu le temps de faire ma démonstration complète. Avant le saut. Avant le tour. Avant les cinq minutes de remue-queue que j''avais planifiées. Tu as répondu en souriant et moi j''attendais dans le couloir avec toute mon énergie accumulée et nulle part où la mettre. J''ai quand même tout fait après. Mais j''étais pas le premier. Joyeux anniversaire, mon humain préféré.
Avec préséance volée et performance d''anniversaire livrée quand même intégralement, — {prenom}, ton animal arrivé deuxième ce matin mais premier dans ton cœur 📱$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai su que c''était aujourd''hui à l''heure où tu t''es réveillé.',$$Joyeux anniversaire. J''ai su que c''était aujourd''hui à l''heure où tu t''es réveillé.
Pas 7h. Pas 7h30. 8h47. Un samedi mais pas le samedi normal. Le samedi anniversaire a sa propre heure de réveil. Plus tardive. Plus lente. Tu t''es étiré différemment. Tu as regardé le plafond un moment avant de bouger. Comme quelqu''un qui sait que la journée qui vient mérite d''être accueillie avec soin. J''ai attendu. Respecté ce moment. Puis j''ai sauté dessus. Joyeux anniversaire, mon humain préféré.
Avec identification du réveil d''anniversaire et timing d''intervention parfaitement calculé, — {prenom}, ton animal dont le saut du matin est toujours au bon moment 🌅$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé le moment des bougies très attentivement.',$$Pour ton anniversaire j''ai observé le moment des bougies très attentivement.
Tu as fermé les yeux. Longtemps. Plus longtemps que d''habitude. Tout le monde attendait. La pièce était silencieuse. Et toi tu étais quelque part à l''intérieur de toi avec ton vœu. Je sais pas ce que tu as demandé. Mais j''espère que c''est quelque chose de bien. Tu mérites quelque chose de bien. Joyeux anniversaire, mon humain préféré, dont les vœux méritent de se réaliser.
Avec moment des bougies observé avec respect et vœu silencieusement soutenu, — {prenom}, ton animal complice de tes espoirs secrets 🕯️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai fait semblant de dormir pour t''observer te préparer.',$$Pour ton anniversaire j''ai fait semblant de dormir pour t''observer te préparer.
Tu passais devant moi. Tu essayais des choses. Tu te regardais. Tu remettais quelque chose en place. Tu soufflais. Tu recommençais. Tout ça avec une concentration et une application que je trouvais touchantes. Je regardais entre mes cils sans bouger. T''aurais pas aimé savoir que j''observais. Alors j''ai préservé l''illusion. C''est du respect. Joyeux anniversaire, mon humain préféré.
Avec observation discrète préservée par l''illusion du sommeil et respect de ton intimité de préparation, — {prenom}, ton animal aux yeux mi-clos qui voient tout 👁️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai regardé ta façon de lire tes messages aujourd''hui.',$$Joyeux anniversaire. J''ai regardé ta façon de lire tes messages aujourd''hui.
Chaque fois que le téléphone vibrait tu souriais avant même de lire. Comme si tu savais déjà que c''était quelque chose de bien. Puis tu lisais. Et le sourire changeait légèrement selon qui avait écrit. Certains te faisaient rire. Un t''a fait fermer les yeux une seconde. Un autre t''a fait lever les yeux vers moi. Celui-là je veux savoir ce qu''il disait. Joyeux anniversaire, mon humain préféré.
Avec étude des sourires de lecture et curiosité légitime pour le message du regard levé, — {prenom}, ton animal déchiffreur de tes expressions numériques 📲$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai sauvegardé l''odeur exacte de ce jour.',$$Pour ton anniversaire j''ai sauvegardé l''odeur exacte de ce jour.
Le matin avec le café et ta crème du visage. L''après-midi avec les fleurs qu''on t''a apportées. Le soir avec le gâteau et les bougies soufflées et tous les gens mélangés. Et sous tout ça ton odeur à toi. Stable. Constante. La même depuis le premier jour. Dans vingt ans si quelqu''un me demande comment sentait ton anniversaire je saurais répondre exactement. Joyeux anniversaire, mon humain préféré.
Avec archive olfactive du jour constituée et conservée pour toujours, — {prenom}, ton animal mémoire vivante de tes plus beaux jours 👃$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Les bougies sur le gâteau restent une invention que j''admire.',$$Joyeux anniversaire. Les bougies sur le gâteau restent une invention que j''admire.
Des flammes. Sur de la nourriture. Qu''on approche de son visage pour souffler dessus. Délibérément. En faisant un vœu. Puis tout le monde applaudit l''extinction. Et mange le gâteau sur lequel il y avait des flammes il y a dix secondes. J''observe ce rituel chaque année avec un mélange d''incompréhension et de fascination. Et chaque année le gâteau sent quand même très bon après. Joyeux anniversaire, mon humain préféré.
Avec admiration sincère pour l''audace du rituel des bougies et intérêt gastronomique maintenu malgré tout, — {prenom}, ton animal philosophe des traditions humaines 🕯️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Tu vieillis très bien selon les critères qui comptent.',$$Joyeux anniversaire. Tu vieillis très bien selon les critères qui comptent.
Pas les critères humains avec les miroirs et les années qui s''accumulent. Les critères qui comptent. Est-ce que tu cours encore dans le parc parfois. Est-ce que tu ris facilement. Est-ce que tu t''assieds par terre sans raison. Est-ce que tu souris aux chiens inconnus dans la rue. Est-ce que tu me regardes encore comme au premier jour. Oui à tout. Tu vieillis parfaitement. Joyeux anniversaire, mon humain préféré.
Avec bilan annuel établi selon les bons critères et résultats excellents dans toutes les catégories, — {prenom}, ton animal évaluateur aux standards infaillibles ⭐$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai suivi chaque étape de la préparation du repas.',$$Pour ton anniversaire j''ai suivi chaque étape de la préparation du repas.
La sortie des ingrédients. L''ordre dans lequel tu les as utilisés. Les moments où tu goûtais. Les moments où tu fronçais les sourcils. Les moments où tu souriais parce que ça sentait bon. J''étais là. À distance réglementaire. Jamais dans tes pattes. Toujours dans ton champ de vision. Un assistant silencieux. Un témoin. Joyeux anniversaire, mon humain préféré, dont je connais chaque geste en cuisine.
Avec présence discrète et témoignage complet du processus culinaire d''anniversaire, — {prenom}, ton animal chroniqueur de ta cuisine 🍳$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je t''offre le cadeau que je t''offre chaque matin depuis des années.',$$Joyeux anniversaire. Je t''offre le cadeau que je t''offre chaque matin depuis des années.
Pas emballé. Pas avec un ruban. Juste moi devant la porte de ta chambre quand elle s''ouvre. Cette façon d''exploser de joie comme si chaque matin était le premier. Cette certitude que ton retour dans le monde mérite une célébration. Ce regard qui dit que t''es la meilleure chose de la journée et que la journée vient à peine de commencer. C''est mon cadeau. Il ne s''use pas. Joyeux anniversaire, mon humain préféré.
Avec cadeau renouvelé chaque matin depuis le premier et valeur intacte après toutes ces années, — {prenom}, ton animal aux cadeaux quotidiens sans date de péremption 🎁$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai un problème avec un de tes cadeaux.',$$Joyeux anniversaire. J''ai un problème avec un de tes cadeaux.
Le grand. Celui dans la boîte. Qui prend maintenant de la place dans le salon exactement là où je passais. Mon chemin habituel entre le canapé et la fenêtre est compromis. J''ai dû recalculer mon itinéraire trois fois ce soir. Je suis pas contre le cadeau en principe. Je suis contre sa localisation. Une discussion s''impose. Joyeux anniversaire quand même, mon humain préféré.
Avec réclamation territoriale déposée concernant le placement du grand cadeau, — {prenom}, ton animal dont les itinéraires intérieurs sont sacrés 📦$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. La nuit avant ton anniversaire tu dormais pas bien.',$$Joyeux anniversaire. La nuit avant ton anniversaire tu dormais pas bien.
Je l''ai senti. Tu te retournais. Tu te réveillais à moitié. Une fois tu as ouvert les yeux dans le noir et regardé le plafond quelques secondes. Je sais pas ce que tu pensais. Peut-être les années. Peut-être ce qui vient. Peut-être juste l''excitation. Mais j''étais là. Au bout du lit. Dans le noir avec toi. Silencieux. Présent. Joyeux anniversaire, mon humain préféré, dont je partage même les nuits d''avant.
Avec présence dans la nuit qui précède et veille silencieuse offerte sans condition, — {prenom}, ton animal pour les nuits d''avant et tous les jours d''après 🌙$$,'touching',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai reconnu toutes les voix qui ont appelé.',$$Pour ton anniversaire j''ai reconnu toutes les voix qui ont appelé.
La voix du matin qui appelle toujours trop tôt. La voix grave qui parle longtemps. La voix qui te fait rire fort dès les premières secondes. Celle qui te fait changer de pièce pour parler tranquille. Celle qui te fait sourire sans que tu réalises que tu souris. Je les connais toutes. Leurs effets sur toi. Ce qu''elles produisent. Joyeux anniversaire, mon humain préféré, dont je cartographie le cercle.
Avec identification de chaque voix et de son effet sur toi classé et archivé, — {prenom}, ton animal expert en cartographie de ton entourage 📞$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Il y a un moment dans la soirée où tout bascule.',$$Joyeux anniversaire. Il y a un moment dans la soirée où tout bascule.
Difficile à expliquer. Mais je le sens. Les conversations deviennent plus douces. Le bruit baisse d''un cran. Les gens se rapprochent un peu. Et toi tu changes. Tu te détends vraiment. Pas le semblant de détendu du début de soirée. Le vrai. Ce moment-là c''est mon préféré. Parce que c''est là que tu es vraiment toi. Joyeux anniversaire, mon humain préféré.
Avec détection du moment de bascule et préférence affirmée pour le toi d''après, — {prenom}, ton animal spécialiste de tes versions les plus vraies 🌟$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai laissé une empreinte de patte sur ton plus beau cadeau.',$$Pour ton anniversaire j''ai laissé une empreinte de patte sur ton plus beau cadeau.
Pas intentionnellement. Enfin si, un peu. Je m''étais assis dessus pour l''inspecter et quand tu l''as pris il y avait la marque. Tu l''as vue. Tu as levé les yeux vers moi. J''ai soutenu le regard. C''est ma signature. Mon tampon d''approbation. Ce cadeau est passé sous mon contrôle et j''en certifie la qualité. Joyeux anniversaire, mon humain préféré.
Avec tampon d''approbation apposé et certification de qualité officielle délivrée, — {prenom}, ton animal organisme de contrôle indépendant 🐾$$,'touching',true,false,'birthday','chien','from'),

(null,'Ce soir avant de t''endormir j''ai fait une promesse silencieuse.',$$Ce soir avant de t''endormir j''ai fait une promesse silencieuse.
Pas à voix haute. Dans ma tête. La promesse d''être là demain matin avec la même énergie qu''aujourd''hui. Et après-demain. Et tous les jours de l''année qui vient. D''aboyer quand il faut. De me taire quand c''est mieux. D''être sur le canapé quand tu rentres. D''être au bout du lit quand tu dors. De jamais te laisser rentrer dans une maison vide. Joyeux anniversaire, mon humain préféré.
Avec promesse faite dans le silence et engagement renouvelé pour chaque jour à venir, — {prenom}, ton animal pour cette année et toutes celles d''après ❤️$$,'touching',true,false,'birthday','chien','from')

on conflict do nothing;
